 namespace WPAICG\Chat\Frontend\Shortcode\ConfiguratorMethods; use WPAICG\Chat\Storage\BotSettingsManager; if (!defined('ABSPATH')) { exit; } function get_conversation_starters_logic(array $settings, bool $starters_ui_enabled): array { $starters_array = []; if ($starters_ui_enabled) { $starters_raw = $settings['conversation_starters'] ?? []; if (!empty($starters_raw) && is_array($starters_raw)) { $starters_array = $starters_raw; } elseif (!empty($starters_raw) && is_string($starters_raw)) { $decoded_starters = json_decode($starters_raw, true); if (is_array($decoded_starters)) { $starters_array = $decoded_starters; } } if (empty($starters_array)) { $starters_array = method_exists(BotSettingsManager::class, 'get_default_conversation_starters') ? BotSettingsManager::get_default_conversation_starters() : [ __('What can you do?', 'gpt3-ai-content-generator'), __('Tell me a fun fact', 'gpt3-ai-content-generator'), ]; } } return $starters_array; } 